def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    a = list(map(int, data[1:1+N]))

    # Arrays to store left and right boundaries
    left = [0] * N
    right = [0] * N

    # Stack for the left pass
    stack = []
    for i in range(N):
        while stack and a[stack[-1]] > a[i]:
            stack.pop()
        if stack:
            left[i] = stack[-1] + 1
        else:
            left[i] = 0
        stack.append(i)

    # Stack for the right pass
    stack = []
    for i in range(N-1, -1, -1):
        while stack and a[stack[-1]] >= a[i]:
            stack.pop()
        if stack:
            right[i] = stack[-1] - 1
        else:
            right[i] = N - 1
        stack.append(i)

    # Calculate the answer
    ans = 0
    for i in range(N):
        ans += a[i] * (i - left[i] + 1) * (right[i] - i + 1)

    print(ans)

