def kosaraju(edges, reverse_edges, v_count):
    visited = [False] * v_count
    order = []

    def dfs1(v):
        visited[v] = True
        for dest in edges[v]:
            if not visited[dest]:
                dfs1(dest)
        order.append(v)

    for v in range(v_count):
        if not visited[v]:
            dfs1(v)

    visited = [False] * v_count
    components = []

    def dfs2(v, comp):
        visited[v] = True
        comp.append(v)
        for dest in reverse_edges[v]:
            if not visited[dest]:
                dfs2(dest, comp)

    for v in reversed(order):
        if not visited[v]:
            comp = []
            dfs2(v, comp)
            components.append(comp)

    return components

