def isPrime(n):
    if n == 2:
        return True
    if n < 2 or n % 2 == 0:
        return False

    # Write n-1 as d*2^s
    d = n - 1
    s = 0
    while d % 2 == 0:
        d //= 2
        s += 1

    # Test with bases: 2, 7, 61
    bases = [2, 7, 61]
    for a in bases:
        if a >= n:
            continue
        x = pow(a, d, n)
        if x == 1 or x == n-1:
            continue
        for _ in range(s-1):
            x = (x * x) % n
            if x == n-1:
                break
        else:
            return False
    return True

