def sieve(n):
    # Create a boolean array for primes up to n
    primes = [True] * (n + 1)
    primes[0] = primes[1] = False

    # Sieve of Eratosthenes
    for i in range(2, int(n**0.5) + 1):
        if primes[i]:
            for j in range(i*i, n + 1, i):
                primes[j] = False
    return primes

def find_max_twin_prime(n, primes):
    # Find the largest twin prime pair <= n
    for i in range(n, 4, -1):
        if primes[i] and primes[i - 2]:
            return (i - 2, i)
    return (3, 5)  # Fallback - smallest twin prime

