def f(n: int) -> int:
    n0 = n - 1
    if n0 == 0:
        return 0
    ans = 0
    a = 1
    while a <= n0:
        q = n0 // a
        a_next = n0 // q + 1
        ans += q * (a_next - a)
        a = a_next
    return ans

