def main():
    import sys
    sys.setrecursionlimit(10**7)
    N, K = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    # Adjust to 0-indexed
    A = [a - 1 for a in A]

    # Build the tree: children list for each node
    children = [[] for _ in range(N)]
    for i in range(1, N):
        parent = A[i]
        children[parent].append(i)

    ans = 0
    if A[0] != 0:
        ans += 1

    def dfs(u):
        nonlocal ans
        max_depth = 0
        for v in children[u]:
            depth = dfs(v)
            if u == 0:
                # For root's children, if depth >= K, we need to break the chain
                if depth >= K:
                    ans += 1
            else:
                if depth >= K - 1:
                    ans += 1
                else:
                    max_depth = max(max_depth, depth)
        return max_depth + 1 if u != 0 else 0

    dfs(0)
    print(ans)

