def solve(A, strt, goal, m):
    cost = [inf] * m
    visited = [False] * m
    cost[strt] = 0
    while True:
        min_val = inf
        next_node = -1
        for i in range(m):
            if not visited[i] and cost[i] < min_val:
                min_val = cost[i]
                next_node = i
        if next_node == -1:
            break
        visited[next_node] = True
        for i in range(m):
            if A[next_node][i] > 0:
                new_cost = cost[next_node] + A[next_node][i]
                if new_cost < cost[i]:
                    cost[i] = new_cost
    return cost[goal]

