def main():
    n, m = map(int, input().split())
    digits = [-1] * n  # -1 means digit not specified yet

    for _ in range(m):
        s, c = map(int, input().split())
        s -= 1  # change to 0-index
        if digits[s] == -1:
            digits[s] = c
        elif digits[s] != c:
            print(-1)
            return

    # Fill unspecified digits with care for leading zeros
    for i in range(n):
        if digits[i] == -1:
            if i == 0:
                # First digit: if n>1, must be at least 1; if n==1, can be 0
                digits[i] = 1 if n > 1 else 0
            else:
                digits[i] = 0
        else:
            # Check leading zero violation for n>1
            if i == 0 and n > 1 and digits[i] == 0:
                print(-1)
                return

    ans = 0
    for d in digits:
        ans = ans * 10 + d

    # Validate that ans has exactly n digits (no leading zeros)
    if n == 1 and 0 <= ans <= 9:
        print(ans)
    elif n > 1 and 10 ** (n - 1) <= ans < 10 ** n:
        print(ans)
    else:
        print(-1)

