class SegTree(object):
    def __init__(self, op, e, n, init_val):
        self.num = 1
        while self.num < n:
            self.num *= 2
        self.S = [e] * (2 * self.num)
        self.op = op
        self.e = e
        for i, v in enumerate(init_val):
            self.S[self.num + i] = v
        for i in range(self.num - 1, 0, -1):
            self.S[i] = self.op(self.S[i * 2], self.S[i * 2 + 1])

    def update(self, index, value):
        idx = self.num + index
        self.S[idx] = value
        while idx > 1:
            idx //= 2
            self.S[idx] = self.op(self.S[idx * 2], self.S[idx * 2 + 1])

    def query(self, l, r):
        res_l = self.e
        res_r = self.e
        l += self.num
        r += self.num
        while l < r:
            if l & 1:
                res_l = self.op(res_l, self.S[l])
                l += 1
            if r & 1:
                r -= 1
                res_r = self.op(self.S[r], res_r)
            l //= 2
            r //= 2
        return self.op(res_l, res_r)

def main():
    import sys
    data = sys.stdin.read().split()
    n = int(data[0])
    K = int(data[1])
    A = list(map(int, data[2:2+n]))

    max_val = 300000
    seg = SegTree(max, 0, max_val + 1, [0] * (max_val + 1))
    ans = 0
    for num in A:
        left = max(0, num - K)
        right = min(max_val, num + K) + 1
        best = seg.query(left, right) + 1
        if best > ans:
            ans = best
        seg.update(num, best)
    print(ans)

